import { MessageEvent } from '@nitrots/nitro-renderer/src/core';
import { JukeboxOpenParser } from '@nitrots/nitro-renderer/src/nitro/communication/messages/parser/JukeboxOpenParser';

export class JukeboxOpenEvent extends MessageEvent {
    constructor(callback: Function) {
        super(callback, JukeboxOpenParser);
    }

    public getParser(): JukeboxOpenParser {
        return this.parser as JukeboxOpenParser;
    }
}
